patch:
--- drivers/net/usb/rndis_host.c	2008-04-17 04:49:44.000000000 +0200
+++ drivers/net/usb/rndis_host.c	2008-05-02 13:49:12.000000000 +0200
@@ -51,6 +51,9 @@
  * currently rare) "Ethernet Emulation Model" (EEM).
  */

+/* SC_* Samsung processors needs an extra timeout */
+#define SC_SLEEP_TIMEOUT		20
+
 /*
  * RNDIS notifications from device: command completion; "reverse"
  * keepalives; etc
@@ -116,6 +119,7 @@
 	rsp = buf->msg_type | RNDIS_MSG_COMPLETION;
 	for (count = 0; count < 10; count++) {
 		memset(buf, 0, CONTROL_BUFFER_SIZE);
+		msleep(SC_SLEEP_TIMEOUT * 10);
 		retval = usb_control_msg(dev->udev,
 			usb_rcvctrlpipe(dev->udev, 0),
 			USB_CDC_GET_ENCAPSULATED_RESPONSE,
@@ -123,6 +127,7 @@
 			0, master_ifnum,
 			buf, CONTROL_BUFFER_SIZE,
 			RNDIS_CONTROL_TIMEOUT_MS);
+		msleep(SC_SLEEP_TIMEOUT * 10);
 		if (likely(retval >= 8)) {
 			msg_len = le32_to_cpu(buf->msg_len);
 			request_id = (__force u32) buf->request_id;
